        try:
            add_windows_dll_search_paths()
        except Exception:
            pass

        ensure_dirs()
        init_db()

        self.log_queue: "queue.Queue[str]" = queue.Queue()
        self.cfg = load_access_app_config()

        # Resolve SDK DLLs
        try:
            self.cfg.plcomm_dll_path = self._resolve_sdk_dll(self.cfg.plcomm_dll_path)
            self.cfg.zkfp_dll_path = self._resolve_sdk_dll(self.cfg.zkfp_dll_path)
        except Exception as e:
            print(f"SDK resource error: {e}\nPlatform: {platform_summary()}")
            raise

        # Enforce 32-bit requirement
        try:
            require_32bit_python_for_32bit_dll(self.cfg.plcomm_dll_path)
        except Exception as e:
            print(f"Architecture error: {e}\nPlatform: {platform_summary()}")
            raise

        self.logger = setup_logging(self.cfg.log_level, ui_queue=self.log_queue)
        self.logger.info("App started.")
        self.logger.info(f"Platform: {platform_summary()}")
        self.logger.info("Data root is managed by app.core.utils (ProgramData/LocalAppData).")
        try:
            config_status = get_access_config_status()
            self.logger.info(
                "Access config: %s (legacyExists=%s migratedAt=%s)",
                config_status.get("liveConfigPath"),
                config_status.get("legacyConfigExists"),
                config_status.get("migratedFromLegacyAt"),
            )
        except Exception:
            self.logger.exception("Failed to read Access config status")
        try:
            storage_status = get_access_storage_status()
            self.logger.info(
                "Access live DB: %s (migration=%s)",
                storage_status.get("liveDbPath"),
                storage_status.get("migrationState"),
            )
        except Exception:
            self.logger.exception("Failed to read Access storage status")
