    # ======================= Headless event loop =======================
    def after(self, delay_ms: int, callback) -> int:
        """Schedule callback after delay_ms milliseconds. Returns an ID."""
        with self._sched_lock:
            self._sched_id_counter += 1
            sid = self._sched_id_counter
            target = time.monotonic() + delay_ms / 1000.0
            self._scheduled.append((target, sid, callback))
        return sid

    def after_cancel(self, sid: int) -> None:
        """Cancel a scheduled callback by ID."""
        with self._sched_lock:
            self._scheduled = [(t, i, c) for t, i, c in self._scheduled if i != sid]

    def mainloop(self) -> None:
        """Run the headless event loop. Blocks until quit_app() is called."""
        while not self._stop_event.is_set():
            now = time.monotonic()
            to_run = []
            with self._sched_lock:
                remaining = []
                for t, sid, cb in self._scheduled:
                    if t <= now:
                        to_run.append(cb)
                    else:
                        remaining.append((t, sid, cb))
                self._scheduled = remaining

            for cb in to_run:
                try:
                    cb()
                except Exception:
                    if hasattr(self, "logger"):
                        self.logger.exception("Scheduled callback error")

            self._stop_event.wait(timeout=0.05)

    def destroy(self) -> None:
        self._stop_event.set()
        # Shutdown ULTRA engine
        try:
            if self._ultra_engine and self._ultra_engine.running:
                self._ultra_engine.stop()
            if self._ultra_history_consumer:
                self._ultra_history_consumer.stop()
                self._ultra_history_consumer = None
        except Exception:
            pass

    def quit(self) -> None:
        self._stop_event.set()

    # ======================= Update Manager =======================
    def _ensure_update_manager_started(self, *, check_now: bool) -> None:
        try:
            auth = load_auth_token()
            tok = getattr(auth, "token", None) if auth else None
            tok = str(tok or "").strip()
            if tok:
                self._update_manager.start(token=tok, check_now=check_now)
            else:
                self._update_manager.stop()
        except Exception:
            pass

    def on_update_status_changed(self, st: UpdateStatus) -> None:
        self._update_status = st

    def on_update_ready(self, st: UpdateStatus) -> None:
        try:
            rid = str((st.latest_release or {}).get("releaseId") or "")
            self.logger.info(f"[Access Update] Update ready: releaseId={rid}")
        except Exception:
            pass

    def on_update_error(self, msg: str) -> None:
        try:
            self.logger.warning("[Access Update] %s", msg)
        except Exception:
            pass

    # ======================= SDK DLL resolution =======================
    def _resolve_sdk_dll(self, configured_path: str) -> str:
        s = (configured_path or "").strip()
        if not s:
            raise FileNotFoundError("Empty DLL path in config")
        try:
            return str(resolve_resource_path(s, must_exist=True))
        except Exception:
            pass
        name = Path(s).name
        try:
            return str(resolve_resource_path(name, must_exist=True))
        except Exception as e:
            raise FileNotFoundError(f"Could not resolve DLL '{s}'. Tried by name '{name}' as well. ({e})")

    # ======================= Per-device mode helpers =======================
    def get_access_mode_summary(self) -> Dict[str, int]:
        cache = load_sync_cache()
        devices = getattr(cache, "devices", []) if cache else []
        dev = ag = ultra = unk = 0
        for d in devices or []:
            if not isinstance(d, dict):
                continue
            raw = d.get("accessDataMode") or d.get("access_data_mode") or ""
            m = str(raw).strip().upper()
            if m == "DEVICE":
                dev += 1
            elif m == "AGENT":
                ag += 1
            elif m == "ULTRA":
                ultra += 1
            else:
                unk += 1
        return {"DEVICE": dev, "AGENT": ag, "ULTRA": ultra, "UNKNOWN": unk}

    # ======================= Log polling =======================
    def _poll_logs(self):
        try:
            while True:
                msg = self.log_queue.get_nowait()
                try:
                    # Parse level from log message format: "2026-... | LEVEL | msg"
                    timestamp = None
                    level = "INFO"
                    line = msg
                    if " | " in msg:
                        parts = msg.split(" | ", 2)
                        if len(parts) >= 3:
                            timestamp = parts[0].strip()
                            level = parts[1].strip()
                            line = parts[2]
                        elif len(parts) >= 2:
                            level = parts[1].strip()
                            line = parts[2] if len(parts) > 2 else parts[1]
                    self.page_logs.append_log(level, line, timestamp=timestamp)
                except Exception:
                    self.page_logs.append_log("INFO", str(msg))
        except Exception:
            pass
        self.after(200, self._poll_logs)

    def _build_startup_command(self) -> str | None:
        try:
            if getattr(sys, "frozen", False):
                return f'"{Path(sys.executable)}" {WINDOWS_STARTUP_ARG}'
            return None
        except Exception:
            return None

    def _sync_startup_registration(self) -> None:
        if os.name != "nt":
            return
        try:
            import winreg  # type: ignore
        except Exception:
            return

        enabled = bool(getattr(self.cfg, "start_on_system_startup", False))
        command = self._build_startup_command()
        run_key_path = r"Software\Microsoft\Windows\CurrentVersion\Run"
        value_name = "MonClubAccess"

        try:
            with winreg.OpenKey(winreg.HKEY_CURRENT_USER, run_key_path, 0, winreg.KEY_SET_VALUE) as key:
                if enabled and command:
                    winreg.SetValueEx(key, value_name, 0, winreg.REG_SZ, command)
                    self.logger.info("Access startup registration enabled.")
                else:
                    try:
                        winreg.DeleteValue(key, value_name)
                        self.logger.info("Access startup registration removed.")
                    except FileNotFoundError:
                        pass
                    if enabled and not command:
                        self.logger.info(
                            "Access startup registration skipped because the app is not running from a packaged executable."
                        )
        except Exception:
            self.logger.exception("Failed to synchronize Access startup registration")

