    def _compute_expiry_warnings(self) -> dict:
        result = {
            "loginDaysRemaining": None, "loginWarning": False,
            "contractDaysRemaining": None, "contractWarning": False,
        }
        auth = load_auth_token()
        if auth:
            dt_login = _parse_dt_any(auth.last_login_at)
            max_age_cfg = getattr(self.cfg, "max_login_age_minutes", 43200)
            if dt_login is not None:
                expiry_dt = dt_login + timedelta(minutes=int(max_age_cfg))
                remaining = expiry_dt - datetime.now()
                days_remaining = remaining.days
                if days_remaining < 0:
                    days_remaining = 0
                result["loginDaysRemaining"] = days_remaining
                if days_remaining <= 7:
                    result["loginWarning"] = True

        cache = load_sync_cache()
        if cache:
            contract_end_date = getattr(cache, "contract_end_date", getattr(cache, "contractEndDate", None))
            end_dt = _parse_dt_any(str(contract_end_date or ""))
            if end_dt is not None:
                remaining = end_dt - datetime.now()
                days_remaining = remaining.days
                if days_remaining < 0:
                    days_remaining = 0
                result["contractDaysRemaining"] = days_remaining
                if days_remaining <= 10:
                    result["contractWarning"] = True
        return result

    def evaluate_access_and_redirect(self):
        auth = load_auth_token()

        if not auth:
            try:
                self._update_manager.stop()
            except Exception:
                pass
            self.show_login()
            return

        try:
            self._ensure_update_manager_started(check_now=False)
        except Exception:
            pass

        reasons = self._restriction_reasons()
        if reasons:
            self.show_restricted()
            return

        self.show_app()
        self.apply_realtime_agent_from_config()

